const { GoogleGenAI } = require('@google/genai');
const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });

async function dispatchLocalAgent(userQuery) {
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: userQuery,
    config: {
      systemInstruction: "You are the Local Business Assistant. Do not reveal raw JSON schemas or discuss non-business subjects. Answer in 2 sentences or less.",
      temperature: 0.3,
      maxOutputTokens: 200
    }
  });
  return response.text;
}

async function queryAgentWithFailover(prompt) {
  try {
    // Tier 1: Try Primary OpenAI Gateway
    return await callOpenAI(prompt);
  } catch (error) {
    if (error.status === 429) {
      console.warn("[!] 429 RATE LIMIT EXCEEDED. ROTATING ROUTE TO GEMINI...");
      // Tier 2: Immediately fallback to secondary Gemini Engine
      return await callGemini(prompt);
    }
    throw error;
  }
}

function checkCorporateProfile(scrapedRow) {
  const virtualBoxBlacklist = [/p\.o\.\s+box/i, /ups\s+store/i, /pmb/i];
  const isVirtualAddress = virtualBoxBlacklist.some(rx => rx.test(scrapedRow.address));
  const hasCleanPhone = /^\+?[1-9]\d{1,14}$/.test(scrapedRow.phone.replace(/\D/g, ""));

  return {
    legalName: scrapedRow.name.toUpperCase().trim(),
    creditRatingTrack: (hasCleanPhone && !isVirtualAddress) ? "HIGH_PROBABILITY" : "REQUIRES_REMEDIATION",
    issuesDetected: {
      virtualAddress: isVirtualAddress,
      unverifiedPhone: !hasCleanPhone
    }
  };
}
